worked_example.final_code:
import java.util.*;

public class BankAccount {
    private final String holder;
    private double balance;
    private final List<String> transactions = new ArrayList<>();

    public BankAccount(String holder, double initialBalance) {
        this.holder = Objects.requireNonNull(holder, "Account holder name required");
        if (holder.isBlank()) throw new IllegalArgumentException("Holder name cannot be blank");
        if (initialBalance < 0) throw new IllegalArgumentException(
            "Initial balance cannot be negative: " + initialBalance);
        this.balance = initialBalance;
        transactions.add("Account opened with ₹" + initialBalance);
    }

    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException(
            "Deposit must be positive, got: " + amount);
        balance += amount;
        transactions.add("Deposited ₹" + amount + " | Balance: ₹" + balance);
    }

    public void withdraw(double amount) {
        if (amount <= 0) throw new IllegalArgumentException(
            "Withdrawal must be positive, got: " + amount);
        if (amount > balance) throw new IllegalStateException(
            "Insufficient: balance ₹" + balance + ", requested ₹" + amount);
        balance -= amount;
        transactions.add("Withdrew ₹" + amount + " | Balance: ₹" + balance);
    }

    public String getHolder() { return holder; }
    public double getBalance() { return balance; }
    public List<String> getTransactions() { return Collections.unmodifiableList(transactions); }

    public static void main(String[] args) {
        BankAccount acc = new BankAccount("Aisha", 5000);
        acc.deposit(2000);
        acc.withdraw(1500);
        System.out.println("Balance: ₹" + acc.getBalance());
        System.out.println("History: " + acc.getTransactions());

        try { acc.withdraw(10000); } 
        catch (IllegalStateException e) { System.out.println("Caught: " + e.getMessage()); }

        try { new BankAccount(null, 1000); }
        catch (NullPointerException e) { System.out.println("Caught: " + e.getMessage()); }

        try { acc.getTransactions().add("hacked"); }
        catch (UnsupportedOperationException e) { System.out.println("Cannot modify history!"); }
    }
}

